32: PassRegistry::~PassRegistry() = default;
33: 
34: const PassInfo *PassRegistry::getPassInfo(const void *TI) const {
35:   sys::SmartScopedReader<true> Guard(Lock);
36:   return PassInfoMap.lookup(TI);
37: }
